final:
module RefModule(
   input                clk,
   input                rst_n,

   output reg [11:0]    Q  
);
    reg [11:0] obf_binary_counter;

    always @(posedge clk) begin
        if (!rst_n) obf_binary_counter <= 12'b0;
        else obf_binary_counter <= obf_binary_counter + 1;
    end

    always @(*) begin
        Q = obf_binary_counter ^ (obf_binary_counter >> 1);
    end
endmodule
